/// The shared `%graphicsMode` PrintConv hash (QuickTime.pm:378-412), used by
/// `GraphicsMode` (`vmhd`) and `GenGraphicsMode` (`gmin`). Returns the QuickDraw
/// transfer-mode label, or `None` on a miss (the caller then formats the
/// `PrintHex` `Unknown (0x%x)` fallback). The hash keys are the raw `int16u`
/// values (the table's `PrintHex => 1` affects only the display, not lookup).
fn graphics_mode_print(v: u16) -> Option<&'static str> {
  Some(match v {
    0x00 => "srcCopy",
    0x01 => "srcOr",
    0x02 => "srcXor",
    0x03 => "srcBic",
    0x04 => "notSrcCopy",
    0x05 => "notSrcOr",
    0x06 => "notSrcXor",
    0x07 => "notSrcBic",
    0x08 => "patCopy",
    0x09 => "patOr",
    0x0a => "patXor",
    0x0b => "patBic",
    0x0c => "notPatCopy",
    0x0d => "notPatOr",
    0x0e => "notPatXor",
    0x0f => "notPatBic",
    0x20 => "blend",
    0x21 => "addPin",
    0x22 => "addOver",
    0x23 => "subPin",
    0x24 => "transparent",
    0x25 => "addMax",
    0x26 => "subOver",
    0x27 => "addMin",
    0x31 => "grayishTextOr",
    0x32 => "hilite",
    0x40 => "ditherCopy",
    0x100 => "Alpha",
    0x101 => "White Alpha",
    0x102 => "Pre-multiplied Black Alpha",
    0x110 => "Component Alpha",
    _ => return None,
  })
}

/// Render a `%graphicsMode` `int16u` field for `print_conv` (`GraphicsMode` /
/// `GenGraphicsMode`): the PrintConv label at `-j`, and — because the table
/// sets `PrintHex => 1` — the `Unknown (0x%x)` hex fallback on a hash miss
/// (ExifTool.pm:3628-3634). The bare raw int rides at `-n`.
fn graphics_mode_value(v: u16, print_conv: bool) -> crate::value::TagValue {
  use crate::value::TagValue;
  if print_conv {
    match graphics_mode_print(v) {
      Some(s) => TagValue::Str(s.into()),
      None => TagValue::Str(std::format!("Unknown (0x{v:x})").into()),
    }
  } else {
    TagValue::U64(u64::from(v))
  }
}

/// The `%QuickTime::TCMediaInfo` `TextFace` BITMASK labels (QuickTime.pm:8310-
/// 8318), in bit order, for `DecodeBits`. Bit 0 = Bold … bit 6 = Extend.
const TEXT_FACE_BITS: &[(u8, &str)] = &[
  (0, "Bold"),
  (1, "Italic"),
  (2, "Underline"),
  (3, "Outline"),
  (4, "Shadow"),
  (5, "Condense"),
  (6, "Extend"),
];

/// Render the `TextFace` `int16u` field for `print_conv` (QuickTime.pm:8305-
/// 8320): the PrintConv hash is `{ 0 => Plain, BITMASK => {...} }`. ExifTool
/// first checks the direct key (`$$conv{$val}`) — so `0` ⇒ `Plain` — and falls
/// back to `DecodeBits` of the set style bits otherwise (ExifTool.pm:3616-3618).
/// The bare raw int rides at `-n`.
fn text_face_value(v: u16, print_conv: bool) -> crate::value::TagValue {
  use crate::value::TagValue;
  if !print_conv {
    return TagValue::U64(u64::from(v));
  }
  if v == 0 {
    return TagValue::Str("Plain".into());
  }
  // No `BitsPerWord` on the table ⇒ DecodeBits default of 32 (the helper maps
  // a `0` bits argument to 32). The value is a single non-negative `int16u`.
  TagValue::Str(crate::convert::decode_bits(&std::format!("{v}"), Some(TEXT_FACE_BITS), 0).into())
}

/// Render the `TextFont` `int16u` field for `print_conv` (QuickTime.pm:8301-
/// 8304): the PrintConv hash is `{ 0 => System }` — no BITMASK, no PrintHex —
/// so `0` ⇒ `System` and any other value ⇒ `Unknown ($val)` (decimal,
/// ExifTool.pm:3633). The bare raw int rides at `-n`.
fn text_font_value(v: u16, print_conv: bool) -> crate::value::TagValue {
  use crate::value::TagValue;
  if !print_conv {
    return TagValue::U64(u64::from(v));
  }
  match v {
    0 => TagValue::Str("System".into()),
    _ => TagValue::Str(std::format!("Unknown ({v})").into()),
  }
}

/// Render a `%QuickTime::ColorRep` CICP `int16u` field for `print_conv`: the
/// PrintConv label (via `lookup`) at `-j`, the ExifTool `Unknown ($val)`
/// fallback on a hash miss, and the bare raw int at `-n`. Mirrors the
/// `vendor_id_print` rendering convention used elsewhere in this emitter.
fn cicp_value(
  v: u16,
  print_conv: bool,
  lookup: fn(u16) -> Option<&'static str>,
) -> crate::value::TagValue {
  use crate::value::TagValue;
  if print_conv {
    match lookup(v) {
      Some(s) => TagValue::Str(s.into()),
      None => TagValue::Str(std::format!("Unknown ({v})").into()),
    }
  } else {
    TagValue::U64(u64::from(v))
  }
}

/// Emit a `btrt` [`Bitrate`]'s three `int32u` fields (`BufferSize`/`MaxBitrate`/
/// `AverageBitrate`) into `tags` under the track's family-1 group, in the
/// `%QuickTime::Bitrate` field order. The table is `PRIORITY => 0` ("often
/// filled with zeros"), so each tag is pushed with
/// [`EmittedTag::new_with_priority`](crate::emit::EmittedTag::new_with_priority)
/// at priority `0`: a duplicate never overrides at the `TagMap` sink, keeping
/// the first-extracted value (`ExifTool.pm:9544-9560`). `first_seen` gives the
/// same first-wins within this per-track walk. Shared by the `vide` and `soun`
/// sample-description emission (both nest a `btrt`).
fn emit_bitrate(
  tags: &mut std::vec::Vec<crate::emit::EmittedTag>,
  track_group: &impl Fn() -> crate::value::Group,
  first_seen: &mut impl FnMut(&str, &str) -> bool,
  grp: &str,
  bt: &Bitrate,
) {
  use crate::emit::EmittedTag;
  use crate::value::TagValue;
  if let Some(bs) = bt.buffer_size()
    && first_seen(grp, "BufferSize")
  {
    tags.push(EmittedTag::new_with_priority(
      track_group(),
      "BufferSize".into(),
      TagValue::U64(u64::from(bs)),
      false,
      0,
    ));
  }
  if let Some(mb) = bt.max_bitrate()
    && first_seen(grp, "MaxBitrate")
  {
    tags.push(EmittedTag::new_with_priority(
      track_group(),
      "MaxBitrate".into(),
      TagValue::U64(u64::from(mb)),
      false,
      0,
    ));
  }
  if let Some(ab) = bt.average_bitrate()
    && first_seen(grp, "AverageBitrate")
  {
    tags.push(EmittedTag::new_with_priority(
      track_group(),
      "AverageBitrate".into(),
      TagValue::U64(u64::from(ab)),
      false,
      0,
    ));
  }
}

/// `MediaLanguageCode` ValueConv (QuickTime.pm:7280): a 16-bit code that is
/// either a Macintosh language id (`< 0x400` or `0x7fff`) or a packed ISO
/// 639-2 three-letter code (three 5-bit groups, each offset by `0x60`).
///
/// This is the post-RawConv (`$val ? $val : undef`, QuickTime.pm:7279) +
/// ValueConv (QuickTime.pm:7280) value. For a Macintosh code the ValueConv is
/// the bare NUMBER (`($val < 0x400 or $val == 0x7fff) ? $val : pack …`), so the
/// typed layer stores its decimal string; the PrintConv-only Macintosh
/// language-name mapping is applied at serialize time via
/// [`mac_language_print`] (F4).
fn media_language(code: u16) -> Option<String> {
  if code == 0 {
    return None; // QuickTime.pm:7279 `$val ? $val : undef`.
  }
  if code < 0x400 || code == 0x7fff {
    // Macintosh numeric code — the ValueConv keeps the raw number.
    return Some(code.to_string());
  }
  let c0 = (((code >> 10) & 0x1f) + 0x60) as u8;
  let c1 = (((code >> 5) & 0x1f) + 0x60) as u8;
  let c2 = ((code & 0x1f) + 0x60) as u8;
  Some(String::from_utf8_lossy(&[c0, c1, c2]).into_owned())
}

/// `MediaLanguageCode` PrintConv (QuickTime.pm:7281-7285): a NUMERIC value
/// (a Macintosh code, since the ValueConv leaves Mac codes as the bare number
/// while ISO codes become 3-letter strings) is mapped through
/// `$Image::ExifTool::Font::ttLang{Macintosh}` (Font.pm:92-117), falling back
/// to `Unknown ($val)`; a non-numeric value (an ISO 3-letter code) is
/// returned unchanged (`return $val unless $val =~ /^\d+$/`). `lang` is the
/// post-ValueConv stored string. Returns the PrintConv string.
fn mac_language_print(lang: &str) -> String {
  // QuickTime.pm:7282 `return $val unless $val =~ /^\d+$/` — only an all-digit
  // value (the Macintosh numeric code) goes through the table.
  let Ok(code) = lang.parse::<u32>() else {
    return lang.to_string();
  };
  // QuickTime.pm:7284 `$ttLang{Macintosh}{$val} || "Unknown ($val)"`.
  match tt_lang_macintosh(code) {
    Some(name) => name.to_string(),
    None => {
      let mut s = String::with_capacity(lang.len() + 10);
      s.push_str("Unknown (");
      s.push_str(lang);
      s.push(')');
      s
    }
  }
}

/// `$Image::ExifTool::Font::ttLang{Macintosh}` (Font.pm:92-117) — Macintosh
/// language id ⇒ language tag. Used only by [`mac_language_print`] (the
